// Import Firestore database
import { db } from '../config/firebase';
import { collection, query, getDocs, getDoc, doc, setDoc, where } from "firebase/firestore";
import React, { Component } from 'react';
import ReactDOM from 'react-dom/client';

async function Read(login) {
    const docRef = doc(db, "City", login);
    const docSnap = await getDoc(docRef);
    
    
    const idArray = []
    const testArray = []
    if (docSnap.exists()) {
      const data = docSnap.data();
      
      const [cleanarray] = Object.values(data)
      

      for (const value of cleanarray) {
        const id = String(value)
        const count = idArray.push(id)
      }

      
        
    } else {
      // doc.data() will be undefined in this case
      console.log("No such document!");
    }

    const test = idArray[1];
    const docRef2 = doc(db, "Routes", test);
    const docSnap2 = await getDoc(docRef2);
    const data2 = docSnap2.data();
    const datajson = JSON.stringify(data2, null, 2)
    const obj2 = JSON.parse(datajson);
    
    var nC = obj2.nameCity;
    var nR = obj2.nameRoute;
    var nbS = obj2.nbrSessions;
    console.log(nC)
    return { _nameCity : nC,
            _nameRoute:nR,
            _nbrSessions:nbS
    }
    
};

const Table1 = () => {
    
    var objx = Read("Leuven");
    console.log(objx._nameCity)
    const obj3 = JSON.stringify(objx, null, 2)
    const obj4 = JSON.parse(obj3);
    
/*     const obj2 = {
        "nameCity": "Leuven",
        "nameRoute": "Test",
        "nbrSessions": "250"
      } */
  
    return (
  
      <>
  
        <div className="stock-container">
  
          {[objx].map((data, key) => {
  
            return (
  
              <div key={key}>
  
                {data.nameCity +
  
                  " , " +
  
                  data.nameRoute +
  
                  ", " +
  
                  data.nbrSessions}
  
              </div>
  
            );
  
          })}
  
        </div>
  
      </>
  
    );
  
  };



export default Table1;
